package pe.org.camaracomercioica.protestos.controller; import jakarta.validation.Valid; import lombok.RequiredArgsConstructor; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import pe.org.camaracomercioica.protestos.dto.*; import pe.org.camaracomercioica.protestos.service.CatalogoService; import java.util.List; @RestController @RequestMapping("/api/entidades") @RequiredArgsConstructor public class EntidadController {private final CatalogoService service;@GetMapping List<EntidadResponse> listar(){return service.entidades();}@PostMapping @ResponseStatus(HttpStatus.CREATED) EntidadResponse crear(@Valid @RequestBody EntidadRequest r){return service.crear(r);}}
